import{_ as e,o as t,c as n,ag as l}from"./chunks/framework.BZohXCq9.js";const g=JSON.parse('{"title":"什么是 Clawline","description":"","frontmatter":{},"headers":[],"relativePath":"guide/what-is.md","filePath":"guide/what-is.md","lastUpdated":null}'),i={name:"guide/what-is.md"};function s(r,a,o,p,d,h){return t(),n("div",null,[...a[0]||(a[0]=[l(`<h1 id="什么是-clawline" tabindex="-1">什么是 Clawline <a class="header-anchor" href="#什么是-clawline" aria-label="Permalink to &quot;什么是 Clawline&quot;">​</a></h1><h2 id="问题" tabindex="-1">问题 <a class="header-anchor" href="#问题" aria-label="Permalink to &quot;问题&quot;">​</a></h2><p>你在用 <a href="https://github.com/openclaw/openclaw" target="_blank" rel="noreferrer">OpenClaw</a> 构建 AI Agent。Agent 运行得很好，但用户怎么用它？</p><p><strong>现有方案的困境：</strong></p><table tabindex="0"><thead><tr><th>方案</th><th>问题</th></tr></thead><tbody><tr><td>依赖 Telegram / Discord</td><td>用户必须安装特定 App；国内访问不友好；UI 不可控；数据在别人手里</td></tr><tr><td>依赖微信公众号</td><td>审核周期长；接口限制多；被封号直接断联</td></tr><tr><td>自己从零搭建</td><td>WebSocket 连接管理、鉴权、消息路由、文件上传、断线重连、流式渲染……工程量巨大</td></tr><tr><td>暴露 Webhook 端口</td><td>Agent 需要公网 IP，内网部署直接不可用</td></tr></tbody></table><p>核心矛盾：<strong>Agent 很强大，但用户触达很困难。</strong></p><h2 id="方案" tabindex="-1">方案 <a class="header-anchor" href="#方案" aria-label="Permalink to &quot;方案&quot;">​</a></h2><p>Clawline 是 OpenClaw 的 <strong>Web 接入方案</strong>，由三个独立组件组成：</p><h3 id="🌐-relay-gateway" tabindex="-1">🌐 Relay Gateway <a class="header-anchor" href="#🌐-relay-gateway" aria-label="Permalink to &quot;🌐 Relay Gateway&quot;">​</a></h3><p><strong>WebSocket 中转网关。</strong> 它是 Agent 和用户之间的桥梁。</p><ul><li>管理所有 WebSocket 连接（客户端 + Agent 后端）</li><li>Token 鉴权，用户管理</li><li>JSON 消息帧转发</li><li>文件上传中转（10MB 限制，7 天 TTL）</li><li>可部署在任意有公网 IP 的机器上</li></ul><h3 id="📡-channel-plugin" tabindex="-1">📡 Channel Plugin <a class="header-anchor" href="#📡-channel-plugin" aria-label="Permalink to &quot;📡 Channel Plugin&quot;">​</a></h3><p><strong>OpenClaw 插件。</strong> 安装到 OpenClaw 节点后，Agent 就能通过 Relay 收发消息。</p><ul><li><code>connectionMode: &quot;relay&quot;</code> —— Agent <strong>主动连出</strong>到 Relay，无需开端口</li><li>消息格式转换（Relay 帧 ↔ OpenClaw 事件）</li><li>流式输出转发</li><li>文件/媒体消息处理</li><li>支持多节点同时连接同一个 Relay</li></ul><h3 id="💬-client-web" tabindex="-1">💬 Client Web <a class="header-anchor" href="#💬-client-web" aria-label="Permalink to &quot;💬 Client Web&quot;">​</a></h3><p><strong>开箱即用的聊天前端。</strong> React + Vite 构建，PWA 支持。</p><ul><li>连接 Relay Gateway 的 WebSocket 端点</li><li>流式消息渲染</li><li>文件发送和接收</li><li>聊天历史 + 断线续传</li><li>移动端自适应</li><li>可定制主题和 UI</li></ul><h2 id="数据流" tabindex="-1">数据流 <a class="header-anchor" href="#数据流" aria-label="Permalink to &quot;数据流&quot;">​</a></h2><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>用户浏览器                  公网服务器                内网 Agent</span></span>
<span class="line"><span>┌──────────┐    wss://    ┌──────────────┐   wss://  ┌──────────────┐</span></span>
<span class="line"><span>│Client Web │ ──────────→ │Relay Gateway │ ←──────── │Channel Plugin│</span></span>
<span class="line"><span>│(React PWA)│ ←────────── │ (中转+鉴权)  │ ────────→ │ (OpenClaw)   │</span></span>
<span class="line"><span>└──────────┘              └──────────────┘           └──────────────┘</span></span>
<span class="line"><span>                               │</span></span>
<span class="line"><span>                          文件上传/下载</span></span>
<span class="line"><span>                          用户 Token 管理</span></span>
<span class="line"><span>                          连接状态监控</span></span></code></pre></div><p><strong>关键设计：</strong> Channel Plugin 主动连接 Relay（箭头方向是 <code>←</code>），而不是 Relay 回调 Agent。这意味着 Agent 可以在任何网络环境运行——内网、VPN、防火墙后面——只要能访问 Relay 的地址。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="./architecture.html">架构概览</a> — 深入了解三端协作机制</li><li><a href="./quickstart.html">快速开始</a> — 5 分钟跑起来</li></ul>`,22)])])}const u=e(i,[["render",s]]);export{g as __pageData,u as default};
